import { parseAttestationBundle, redactAttestationForSignal } from '../src/github-attestation';
import { normalizeGateDecisionForOutput } from '../src/public-api';

describe('parseAttestationBundle', () => {
  it('requires bundle.verified for cryptographic verified', () => {
    const without = parseAttestationBundle({
      bundle: { verified: false },
      statement: { predicateType: 'https://slsa.dev/provenance/v1', subject: [{ digest: { sha256: 'a'.repeat(64) } }] },
    });
    expect(without.bundleVerified).toBe(false);

    const withVerified = parseAttestationBundle({
      bundle: { verified: true },
      statement: { predicateType: 'https://slsa.dev/provenance/v1', subject: [{ digest: { sha256: 'b'.repeat(64) } }] },
    });
    expect(withVerified.bundleVerified).toBe(true);
  });

  it('redacts raw attestation payloads', () => {
    const redacted = redactAttestationForSignal({
      bundle: { verified: true, signatures: ['secret'] },
      statement: { predicateType: 'x', subject: [{ digest: { sha256: 'c'.repeat(64) } }] },
    });
    expect(redacted).not.toHaveProperty('signatures');
    expect(redacted.bundleVerified).toBe(true);
  });
});

describe('normalizeGateDecisionForOutput', () => {
  it('maps allow/warn/block', () => {
    expect(normalizeGateDecisionForOutput('allow')).toBe('ALLOW');
    expect(normalizeGateDecisionForOutput('warn')).toBe('WARN');
    expect(normalizeGateDecisionForOutput('block')).toBe('BLOCK');
  });
});
